/**
 * @summary Get audit log (admin only)
 */
export const getGetAuditLogUrl = (params?: GetAuditLogParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/system/audit-log?${stringifiedParams}`
    : `/api/system/audit-log`;
};

export const getAuditLog = async (
  params?: GetAuditLogParams,
  options?: RequestInit,
): Promise<AuditLogEntry[]> => {
  return customFetch<AuditLogEntry[]>(getGetAuditLogUrl(params), {
    ...options,
    method: "GET",
  });
};

